UPDATE produits_complementaires SET phrase_conseil = sub.phrase
FROM (VALUES ('50964373-396f-497d-a04a-243396a82b1f'::uuid, 'La fatigue nerveuse peut être un symptôme associé, le magnésium marin et la B6 aident à réduire l''irritabilité nerveuse.'),('0edbf550-a24e-4673-a61e-dc8bd5dc30da'::uuid, 'Le traitement peut augmenter la fatigue nerveuse, le magnésium aide à réguler le système nerveux et à réduire l''irritabilité associée.'),('b075bb64-9d47-4d67-8ee1-d5a98befffbd'::uuid, 'Les antifongiques peuvent assécher la peau, cette crème émolliente aide à restaurer la barrière cutanée pour apaiser les irritations.'),('097bff75-0fb2-46b0-9614-65a8e7cc51dd'::uuid, 'Les antifongiques peuvent assécher la peau, cette crème émolliente aide à restaurer la barrière cutanée pour apaiser les irritations.'),('def04d91-eaad-4508-85fa-03da11f07612'::uuid, 'Les antifongiques peuvent assécher la peau, cette crème émolliente aide à restaurer la barrière cutanée pour apaiser les irritations.'),('0205818c-3a3e-4b1d-8f99-e6b64950063a'::uuid, 'Le traitement peut affecter la santé cardiovasculaire, les Oméga 3 aident à maintenir l''élasticité vasculaire et la fonction cardiaque.'),('2a159e17-e5b2-4db1-903d-bd88cf617146'::uuid, 'Certains traitements peuvent impacter la vitalité cellulaire, la Coenzyme Q10 participe à la production d''énergie cardiaque pour la protéger.'),('402be449-b7b8-42eb-944e-9e47193cf3c7'::uuid, 'Pour surveiller l''efficacité du traitement, ce tensiomètre permet une mesure précise de la pression artérielle à domicile.'),('366adabd-e2ef-4429-959f-9e53a8524e1e'::uuid, 'Les antimétabolites peuvent affaiblir l''immunité, la vitamine D3 aide à renforcer le système immunitaire pour mieux se défendre.'),('e9f066d5-7c51-4a00-992f-f700d517d826'::uuid, 'Le traitement peut générer de la fatigue, le magnésium aide à réduire la lassitude et à maintenir un bon équilibre nerveux.'),('7f407be9-1ef7-4efc-96a8-8fbdcce41171'::uuid, 'Les antimétabolites peuvent déséquilibrer la flore intestinale, les probiotiques aident à restaurer l''équilibre digestif et l''immunité associée.'),('f6b9167f-2b72-422a-a4ba-bd9dda8b27f3'::uuid, 'Certains traitements peuvent affecter l''immunité, la vitamine D3 aide à soutenir les défenses de l''organisme et la minéralisation osseuse.'),('c3dda861-ed88-4251-88f9-87f352393eec'::uuid, 'Les antimigraineux peuvent entraîner de la fatigue, le magnésium aide à réguler la transmission nerveuse et à apaiser la tension.'),('3c424759-4426-46ae-acd3-b5008799ff27'::uuid, 'Les antimigraineux peuvent impacter la flore digestive, les probiotiques aident à maintenir un microbiote équilibré et une bonne digestion.'),('1fdedc63-f62e-4d1b-adf3-1736e11fbddd'::uuid, 'Les os nécessitent du soutien, la vitamine D3 assure l''absorption du calcium et favorise une meilleure densité osseuse.'),('d2439257-1f0c-47de-9dad-f3fcecb4a11e'::uuid, 'La fragilité osseuse est une préoccupation, le calcium et le magnésium aident à renforcer la structure osseuse pour les maintenir solides.'),('699efe99-0cd6-45c9-b23a-e371f9b9720c'::uuid, 'L''ostéoporose peut être associée à un stress oxydatif, ce duo aide à protéger les cellules et à soutenir l''organisme.'),('8a02b3c2-c399-4ae2-aae4-4b4e76c76d28'::uuid, 'Les antiparkinsoniens peuvent causer de la nervosité ou de la fatigue, le magnésium aide à réguler le système nerveux et les tensions musculaires.'),('9c2efa79-839a-4d27-ab73-4cecde8d9f66'::uuid, 'Les troubles du sommeil peuvent accompagner la maladie, la mélatonine aide à réguler le cycle veille-sommeil et facilite l''endormissement.'),('c8105831-aead-4051-8f3b-5254fc3041db'::uuid, 'La tension et les difficultés à dormir sont fréquentes, la lavande aide à induire la relaxation et favorise un sommeil apaisant.'),('eecdc68d-b172-49b9-bb87-edfe1e05ee00'::uuid, 'Les antipsychotiques peuvent entraîner de l''agitation, le magnésium aide à apaiser le système nerveux et à réduire la nervosité.'),('50da6f37-fc25-456e-baea-e63de6716421'::uuid, 'Les antipsychotiques peuvent entraîner de l''agitation, le magnésium aide à apaiser le système nerveux et à réduire la nervosité.'),('0fff2b9e-4577-4101-892e-c7cdbba33f9b'::uuid, 'Les antipsychotiques peuvent entraîner de l''agitation, le magnésium aide à apaiser le système nerveux et à réduire la nervosité.'),('661073b8-cade-4bd8-9924-85f429ba78af'::uuid, 'Les antiseptiques intestinaux peuvent altérer la flore, ces probiotiques aident à restaurer l''équilibre du microbiote digestif.'),('f252b2e5-f1ba-44cb-b858-0a54476b7941'::uuid, 'Les antiseptiques intestinaux peuvent irriter la muqueuse, le Smecta aide à former une barrière protectrice pour apaiser l''intestin.'),('a764a9f8-a02d-42bc-b502-ad39f6c9ed10'::uuid, 'Après la prise d''antiseptiques intestinaux, cette tisane aide à apaiser les spasmes digestifs et à faciliter la digestion.'),('51b25d7a-5e27-4362-be3d-e41630869b7f'::uuid, 'Les antispasmodiques vésicaux ne préviennent pas les infections, l''extrait de cranberry aide à empêcher la fixation des bactéries dans les voies urinaires.'),('93afd521-af1d-4931-be71-f5a2ac59be4e'::uuid, 'Les traitements peuvent perturber la flore intime, ces probiotiques aident à restaurer l''équilibre du microbiome urogénital.'),('8241020a-df36-43e3-8631-4ced235bf5ef'::uuid, 'Les infections urinaires sont fréquentes, le D-Mannose aide à bloquer l''adhésion des bactéries pathogènes aux parois de la vessie.'),('e06a475a-552e-4287-af9f-ebdf34143312'::uuid, 'La toux est souvent associée à une congestion nasale, un spray hypertonique aide à désencombrer les voies aériennes naturellement.')) AS sub(id, phrase)
WHERE produits_complementaires.id = sub.id;